+    const created = createObligation(db, {
+      category: '税務',
+      title: '青色申告承認申請',
+      description: '提出期限を確認する',
+      dueDate: '2026-03-15',
+      recurrence: 'yearly',
+      sourceId: 'S2',
+    });
