+
+let app: FastifyInstance;
+let db: DB;
+
+beforeEach(async () => {
+  db = bootstrap({ filename: ':memory:' });
+  app = Fastify({ logger: false });
+  app.decorate('db', db);
+  await app.register(obligationRoutes);
+});
+
+afterEach(async () => {
+  await app.close();
+  db.close();
