+
+function mapRow(row: ObligationRow): {
+  id: number;
+  category: string;
+  title: string;
+  description: string | null;
+  dueDate: string | null;
+  recurrence: string | null;
+  status: string;
+  sourceId: string | null;
+  evidenceAttachmentId: number | null;
