index 0000000000000000000000000000000000000000..6f5328f4e7012c5b14ec1423faf2065f313a2dc2
--- /dev/null
+++ b/packages/core/src/seed/checklist.ts
@@ -0,0 +1,94 @@
+import { existsSync, readFileSync } from 'node:fs';
+import { dirname, join } from 'node:path';
+import { fileURLToPath } from 'node:url';
+import type { DB } from '../db/connection.js';
+import { parseCsv, type CsvRow } from '../util/csv.js';
+import { createObligation, updateObligation } from '../services/obligations.js';
+
+export interface SeedChecklistResult {
+  inserted: number;
+  updated: number;
+  total: number;
+}
+
+const SOURCE_PATTERN = /S(?:1[0-5]|[1-9])/g;
+
+export function seedChecklist(db: DB, csvPath = defaultChecklistPath()): SeedChecklistResult {
+  const rows = parseCsv(readFileSync(csvPath, 'utf8'));
+  let inserted = 0;
+  let updated = 0;
+
+  const tx = db.transaction(() => {
+    for (const row of rows) {
+      const input = toObligationInput(row);
+      const existing = db
+        .prepare('SELECT id FROM obligations WHERE category = ? AND title = ?')
+        .get(input.category, input.title) as { id: number } | undefined;
+      if (existing) {
+        updateObligation(db, existing.id, input, 'seed');
+        updated++;
+      } else {
+        createObligation(db, input, 'seed');
+        inserted++;
+      }
+    }
+  });
+  tx();
+
+  return { inserted, updated, total: rows.length };
+}
+
+function toObligationInput(row: CsvRow): {
+  category: string;
+  title: string;
+  description: string;
+  dueDate: null;
+  recurrence: null;
+  status: string;
+  sourceId: string | null;
+  evidenceAttachmentId: null;
+} {
+  const phase = required(row, 'フェーズ');
+  const category = required(row, '分類');
+  const task = required(row, 'タスク');
+  const priority = row['優先度']?.trim() || '未設定';
+  const evidence = row['証跡/成果物']?.trim() || '未設定';
+  const status = normalizeStatus(row['状態']);
+  const sourceId = firstSourceId(row['主な出典'] ?? '');
+
+  return {
+    category,
+    title: task,
+    description: `フェーズ: ${phase}\n優先度: ${priority}\n証跡/成果物: ${evidence}`,
+    dueDate: null,
+    recurrence: null,
+    status,
+    sourceId,
+    evidenceAttachmentId: null,
+  };
+}
+
+function defaultChecklistPath(): string {
+  const candidates = [
+    join(process.cwd(), 'docs', 'reference', 'action_checklist.csv'),
+    join(dirname(fileURLToPath(import.meta.url)), '..', '..', '..', '..', 'docs', 'reference', 'action_checklist.csv'),
+  ];
+  const found = candidates.find((candidate) => existsSync(candidate));
+  if (!found) throw new Error('docs/reference/action_checklist.csv not found');
+  return found;
+}
+
+function required(row: CsvRow, key: string): string {
+  const value = row[key]?.trim();
+  if (!value) throw new Error(`checklist column is required: ${key}`);
+  return value;
+}
+
+function normalizeStatus(value: string | undefined): string {
+  const status = value?.trim();
+  return status && status !== '未' ? status : '未着手';
+}
+
+function firstSourceId(value: string): string | null {
+  return value.match(SOURCE_PATTERN)?.[0] ?? null;
+}
diff --git a/packages/core/src/services/obligations.ts b/packages/core/src/services/obligations.ts
new file mode 100755
index 0000000000000000000000000000000000000000..bf545799442622ccbb6f69063505c40d690c6802
--- /dev/null
+++ b/packages/core/src/services/obligations.ts
@@ -0,0 +1,183 @@
+import { writeAudit } from '../audit.js';
+import type { DB } from '../db/connection.js';
+import { dueStatus, type DueStatus, type IsoDate } from '../util/dates.js';
+
+export interface Obligation {
+  id: number;
+  category: string;
+  title: string;
+  description: string | null;
+  dueDate: IsoDate | null;
+  recurrence: string | null;
+  status: string;
+  sourceId: string | null;
+  evidenceAttachmentId: number | null;
+  createdAt: string;
+}
+
+export interface ObligationWithDueStatus extends Obligation {
+  dueStatus: DueStatus;
+}
+
+export interface CreateObligationInput {
+  category: string;
+  title: string;
+  description?: string | null;
+  dueDate?: IsoDate | null;
+  recurrence?: string | null;
+  status?: string;
+  sourceId?: string | null;
+  evidenceAttachmentId?: number | null;
+}
+
+export type UpdateObligationInput = Partial<CreateObligationInput>;
+
+interface ObligationRow {
+  id: number;
+  category: string;
+  title: string;
+  description: string | null;
+  due_date: string | null;
+  recurrence: string | null;
+  status: string;
+  source_id: string | null;
+  evidence_attachment_id: number | null;
+  created_at: string;
+}
+
+const ENTITY_TYPE = 'obligation';
+
+export function createObligation(db: DB, input: CreateObligationInput, actor = 'local_user'): Obligation {
+  const payload = normalizeCreate(input);
+  const result = db
+    .prepare(
+      `INSERT INTO obligations
+        (category, title, description, due_date, recurrence, status, source_id, evidence_attachment_id)
+       VALUES
+        (@category, @title, @description, @dueDate, @recurrence, @status, @sourceId, @evidenceAttachmentId)`,
+    )
+    .run(payload);
+  const created = getObligationOrThrow(db, Number(result.lastInsertRowid));
+  writeAudit(db, { actor, action: 'create', entityType: ENTITY_TYPE, entityId: created.id, after: created });
+  return created;
+}
+
+export function getObligation(db: DB, id: number): Obligation | null {
+  const row = db.prepare('SELECT * FROM obligations WHERE id = ?').get(id) as ObligationRow | undefined;
+  return row ? mapRow(row) : null;
+}
+
+export function listObligations(db: DB): Obligation[] {
+  return db
+    .prepare('SELECT * FROM obligations ORDER BY due_date IS NULL, due_date ASC, id ASC')
+    .all()
+    .map((row) => mapRow(row as ObligationRow));
+}
+
+export function listWithDueStatus(db: DB, today: IsoDate): ObligationWithDueStatus[] {
+  return listObligations(db).map((obligation) => ({
+    ...obligation,
+    dueStatus: dueStatus(obligation.dueDate, today),
+  }));
+}
+
+export function updateObligation(db: DB, id: number, input: UpdateObligationInput, actor = 'local_user'): Obligation {
+  const before = getObligationOrThrow(db, id);
+  const next = { ...before, ...normalizeUpdate(input) };
+  db.prepare(
+    `UPDATE obligations SET
+       category = @category,
+       title = @title,
+       description = @description,
+       due_date = @dueDate,
+       recurrence = @recurrence,
+       status = @status,
+       source_id = @sourceId,
+       evidence_attachment_id = @evidenceAttachmentId
+     WHERE id = @id`,
+  ).run({
+    id,
+    category: next.category,
+    title: next.title,
+    description: next.description,
+    dueDate: next.dueDate,
+    recurrence: next.recurrence,
+    status: next.status,
+    sourceId: next.sourceId,
+    evidenceAttachmentId: next.evidenceAttachmentId,
+  });
+  const after = getObligationOrThrow(db, id);
+  writeAudit(db, { actor, action: 'update', entityType: ENTITY_TYPE, entityId: id, before, after });
+  return after;
+}
+
+export function updateObligationStatus(db: DB, id: number, status: string, actor = 'local_user'): Obligation {
+  return updateObligation(db, id, { status }, actor);
+}
+
+export function deleteObligation(db: DB, id: number, actor = 'local_user'): void {
+  const before = getObligationOrThrow(db, id);
+  writeAudit(db, { actor, action: 'delete', entityType: ENTITY_TYPE, entityId: id, before });
+  db.prepare('DELETE FROM obligations WHERE id = ?').run(id);
+}
+
+function getObligationOrThrow(db: DB, id: number): Obligation {
+  const obligation = getObligation(db, id);
+  if (!obligation) throw new Error(`obligation not found: ${id}`);
+  return obligation;
+}
+
+function normalizeCreate(input: CreateObligationInput): Required<CreateObligationInput> {
+  const category = requireText(input.category, 'category');
+  const title = requireText(input.title, 'title');
+  return {
+    category,
+    title,
+    description: toNullableText(input.description),
+    dueDate: toNullableText(input.dueDate),
+    recurrence: toNullableText(input.recurrence),
+    status: toNullableText(input.status) ?? '未着手',
+    sourceId: toNullableText(input.sourceId),
+    evidenceAttachmentId: input.evidenceAttachmentId ?? null,
+  };
+}
+
+function normalizeUpdate(input: UpdateObligationInput): UpdateObligationInput {
+  const out: UpdateObligationInput = {};
+  if (input.category !== undefined) out.category = requireText(input.category, 'category');
+  if (input.title !== undefined) out.title = requireText(input.title, 'title');
+  if (input.description !== undefined) out.description = toNullableText(input.description);
+  if (input.dueDate !== undefined) out.dueDate = toNullableText(input.dueDate);
+  if (input.recurrence !== undefined) out.recurrence = toNullableText(input.recurrence);
+  if (input.status !== undefined) out.status = requireText(input.status, 'status');
+  if (input.sourceId !== undefined) out.sourceId = toNullableText(input.sourceId);
+  if (input.evidenceAttachmentId !== undefined) out.evidenceAttachmentId = input.evidenceAttachmentId;
+  return out;
+}
+
+function requireText(value: string | null | undefined, field: string): string {
+  const text = toNullableText(value);
+  if (!text) throw new Error(`${field} is required`);
+  return text;
+}
+
+function toNullableText(value: string | null | undefined): string | null {
+  if (value == null) return null;
+  const text = value.trim();
+  return text.length > 0 ? text : null;
+}
+
+function mapRow(row: ObligationRow): Obligation {
+  return {
+    id: row.id,
+    category: row.category,
+    title: row.title,
+    description: row.description,
+    dueDate: row.due_date,
+    recurrence: row.recurrence,
+    status: row.status,
+    sourceId: row.source_id,
+    evidenceAttachmentId: row.evidence_attachment_id,
+    createdAt: row.created_at,
+  };
+}
diff --git a/packages/core/test/obligations.test.ts b/packages/core/test/obligations.test.ts
new file mode 100755
index 0000000000000000000000000000000000000000..7257553ff00811bcc148e4334a5c2a61d8e515a6
--- /dev/null
+++ b/packages/core/test/obligations.test.ts
@@ -0,0 +1,79 @@
+import { describe, expect, it } from 'vitest';
+import { bootstrap } from '../src/db/bootstrap.js';
+import {
+  createObligation,
+  deleteObligation,
+  getObligation,
+  listWithDueStatus,
+  updateObligation,
+  updateObligationStatus,
+} from '../src/services/obligations.js';
+import { seedChecklist } from '../src/seed/checklist.js';
+
+describe('obligations service', () => {
+  it('CRUD と監査ログを記録する', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    const created = createObligation(db, {
+      category: '税務',
+      title: '青色申告承認申請',
+      description: '提出期限を確認する',
+      dueDate: '2026-03-15',
+      recurrence: 'yearly',
+      sourceId: 'S2',
+    });
+
+    expect(created.id).toBeGreaterThan(0);
+    expect(created.status).toBe('未着手');
+    expect(getObligation(db, created.id)?.sourceId).toBe('S2');
+
+    const updated = updateObligation(db, created.id, { title: '青色申告承認申請書', status: '進行中' });
+    expect(updated.title).toBe('青色申告承認申請書');
+    expect(updated.status).toBe('進行中');
+
+    const statusUpdated = updateObligationStatus(db, created.id, '完了');
+    expect(statusUpdated.status).toBe('完了');
+
+    deleteObligation(db, created.id);
+    expect(getObligation(db, created.id)).toBeNull();
+
+    const audit = db
+      .prepare('SELECT action FROM audit_logs WHERE entity_type = ? ORDER BY id')
+      .all('obligation')
+      .map((row) => (row as { action: string }).action);
+    expect(audit).toEqual(['create', 'update', 'update', 'delete']);
+    db.close();
+  });
+
+  it('listWithDueStatus は dates.ts の期限判定を付与する', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    createObligation(db, { category: '期限', title: '超過', dueDate: '2026-06-08' });
+    createObligation(db, { category: '期限', title: '近い', dueDate: '2026-06-20' });
+    createObligation(db, { category: '期限', title: '先', dueDate: '2026-07-01' });
+    createObligation(db, { category: '期限', title: '未設定' });
+
+    const byTitle = new Map(listWithDueStatus(db, '2026-06-09').map((item) => [item.title, item.dueStatus]));
+    expect(byTitle.get('超過')).toBe('overdue');
+    expect(byTitle.get('近い')).toBe('due_soon');
+    expect(byTitle.get('先')).toBe('upcoming');
+    expect(byTitle.get('未設定')).toBe('none');
+    db.close();
+  });
+
+  it('seedChecklist は CSV から冪等に投入し source_id を紐付ける', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    const first = seedChecklist(db);
+    const second = seedChecklist(db);
+    const count = db.prepare('SELECT COUNT(*) AS n FROM obligations').get() as { n: number };
+    const blueReturn = db.prepare('SELECT source_id FROM obligations WHERE category = ?').get('青色申告') as {
+      source_id: string;
+    };
+
+    expect(first.inserted).toBeGreaterThan(0);
+    expect(first.total).toBeGreaterThan(0);
+    expect(second.inserted).toBe(0);
+    expect(second.updated).toBe(first.total);
+    expect(count.n).toBe(first.total);
+    expect(blueReturn.source_id).toBe('S1');
+    db.close();
+  });
+});
diff --git a/packages/server/src/routes/obligations.ts b/packages/server/src/routes/obligations.ts
new file mode 100755
index 0000000000000000000000000000000000000000..930266ae903dc9d510ffd51278797e932ee10831
--- /dev/null
+++ b/packages/server/src/routes/obligations.ts
@@ -0,0 +1,270 @@
+import type { FastifyInstance } from 'fastify';
+import { dueStatus, toIsoDate } from '@free-worker/core';
+
+interface ObligationRow {
+  id: number;
+  category: string;
+  title: string;
+  description: string | null;
+  due_date: string | null;
+  recurrence: string | null;
+  status: string;
+  source_id: string | null;
+  evidence_attachment_id: number | null;
+  created_at: string;
+}
+
+interface ObligationPayload {
+  category?: string;
+  title?: string;
+  description?: string | null;
+  dueDate?: string | null;
+  recurrence?: string | null;
+  status?: string;
+  sourceId?: string | null;
+  evidenceAttachmentId?: number | null;
+}
+
+export async function obligationRoutes(app: FastifyInstance): Promise<void> {
+  app.get('/api/obligations', async (req) => {
+    const query = req.query as { today?: string };
+    const today = query.today ?? toIsoDate(new Date());
+    return app.db
+      .prepare('SELECT * FROM obligations ORDER BY due_date IS NULL, due_date ASC, id ASC')
+      .all()
+      .map((row) => {
+        const obligation = mapRow(row as ObligationRow);
+        return { ...obligation, dueStatus: dueStatus(obligation.dueDate, today) };
+      });
+  });
+
+  app.get('/api/obligations/:id', async (req, reply) => {
+    const id = routeId(req.params);
+    if (!Number.isInteger(id)) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const obligation = getObligation(app, id);
+    if (!obligation) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    return obligation;
+  });
+
+  app.post('/api/obligations', async (req, reply) => {
+    const body = (req.body ?? {}) as ObligationPayload;
+    const validation = validateCreate(body);
+    if (validation) {
+      reply.code(400);
+      return validation;
+    }
+    const result = app.db
+      .prepare(
+        `INSERT INTO obligations
+          (category, title, description, due_date, recurrence, status, source_id, evidence_attachment_id)
+         VALUES
+          (@category, @title, @description, @dueDate, @recurrence, @status, @sourceId, @evidenceAttachmentId)`,
+      )
+      .run(normalizePayload(body, true));
+    const created = getObligation(app, Number(result.lastInsertRowid));
+    app.db
+      .prepare(
+        `INSERT INTO audit_logs (actor, action, entity_type, entity_id, before_json, after_json)
+         VALUES (@actor, @action, @entityType, @entityId, @before, @after)`,
+      )
+      .run({
+        actor: 'local_user',
+        action: 'create',
+        entityType: 'obligation',
+        entityId: String(result.lastInsertRowid),
+        before: null,
+        after: JSON.stringify(created),
+      });
+    reply.code(201);
+    return created;
+  });
+
+  app.put('/api/obligations/:id', async (req, reply) => {
+    const id = routeId(req.params);
+    if (!Number.isInteger(id)) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getObligation(app, id);
+    if (!before) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    const body = (req.body ?? {}) as ObligationPayload;
+    const validation = validateUpdate(body);
+    if (validation) {
+      reply.code(400);
+      return validation;
+    }
+    const next = { ...before, ...normalizeUpdatePayload(body) };
+    app.db
+      .prepare(
+        `UPDATE obligations SET
+           category = @category,
+           title = @title,
+           description = @description,
+           due_date = @dueDate,
+           recurrence = @recurrence,
+           status = @status,
+           source_id = @sourceId,
+           evidence_attachment_id = @evidenceAttachmentId
+         WHERE id = @id`,
+      )
+      .run({ ...next, id });
+    const after = getObligation(app, id);
+    writeRouteAudit(app, 'update', id, before, after);
+    return after;
+  });
+
+  app.patch('/api/obligations/:id/status', async (req, reply) => {
+    const id = routeId(req.params);
+    if (!Number.isInteger(id)) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getObligation(app, id);
+    if (!before) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    const body = (req.body ?? {}) as { status?: string };
+    if (!body.status?.trim()) {
+      reply.code(400);
+      return { error: 'status_required' };
+    }
+    app.db.prepare('UPDATE obligations SET status = @status WHERE id = @id').run({ id, status: body.status.trim() });
+    const after = getObligation(app, id);
+    writeRouteAudit(app, 'update', id, before, after);
+    return after;
+  });
+
+  app.delete('/api/obligations/:id', async (req, reply) => {
+    const id = routeId(req.params);
+    if (!Number.isInteger(id)) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getObligation(app, id);
+    if (!before) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    writeRouteAudit(app, 'delete', id, before, undefined);
+    app.db.prepare('DELETE FROM obligations WHERE id = ?').run(id);
+    reply.code(204);
+    return undefined;
+  });
+}
+
+function getObligation(app: FastifyInstance, id: number): ReturnType<typeof mapRow> | null {
+  const row = app.db.prepare('SELECT * FROM obligations WHERE id = ?').get(id) as ObligationRow | undefined;
+  return row ? mapRow(row) : null;
+}
+
+function writeRouteAudit(
+  app: FastifyInstance,
+  action: string,
+  entityId: number,
+  before: unknown,
+  after: unknown,
+): void {
+  app.db
+    .prepare(
+      `INSERT INTO audit_logs (actor, action, entity_type, entity_id, before_json, after_json)
+       VALUES (@actor, @action, @entityType, @entityId, @before, @after)`,
+    )
+    .run({
+      actor: 'local_user',
+      action,
+      entityType: 'obligation',
+      entityId: String(entityId),
+      before: before === undefined ? null : JSON.stringify(before),
+      after: after === undefined ? null : JSON.stringify(after),
+    });
+}
+
+function validateCreate(body: ObligationPayload): { error: string } | null {
+  if (!body.category?.trim()) return { error: 'category_required' };
+  if (!body.title?.trim()) return { error: 'title_required' };
+  return null;
+}
+
+function validateUpdate(body: ObligationPayload): { error: string } | null {
+  if (body.category !== undefined && !body.category?.trim()) return { error: 'category_required' };
+  if (body.title !== undefined && !body.title?.trim()) return { error: 'title_required' };
+  if (body.status !== undefined && !body.status?.trim()) return { error: 'status_required' };
+  return null;
+}
+
+function normalizePayload(body: ObligationPayload, fillDefaults: true): Record<string, string | number | null> {
+  return {
+    category: trimText(body.category) ?? '',
+    title: trimText(body.title) ?? '',
+    description: nullableText(body.description),
+    dueDate: nullableText(body.dueDate),
+    recurrence: nullableText(body.recurrence),
+    status: trimText(body.status) ?? '未着手',
+    sourceId: nullableText(body.sourceId),
+    evidenceAttachmentId: body.evidenceAttachmentId ?? null,
+  };
+}
+
+function normalizeUpdatePayload(body: ObligationPayload): Record<string, string | number | null> {
+  const out: Record<string, string | number | null> = {};
+  if (body.category !== undefined) out.category = trimText(body.category) ?? '';
+  if (body.title !== undefined) out.title = trimText(body.title) ?? '';
+  if (body.description !== undefined) out.description = nullableText(body.description);
+  if (body.dueDate !== undefined) out.dueDate = nullableText(body.dueDate);
+  if (body.recurrence !== undefined) out.recurrence = nullableText(body.recurrence);
+  if (body.status !== undefined) out.status = trimText(body.status) ?? '';
+  if (body.sourceId !== undefined) out.sourceId = nullableText(body.sourceId);
+  if (body.evidenceAttachmentId !== undefined) out.evidenceAttachmentId = body.evidenceAttachmentId;
+  return out;
+}
+
+function routeId(params: unknown): number {
+  return Number((params as { id: string }).id);
+}
+
+function nullableText(value: string | null | undefined): string | null {
+  if (value == null) return null;
+  return trimText(value);
+}
+
+function trimText(value: string | null | undefined): string | null {
+  if (value == null) return null;
+  const text = value.trim();
+  return text.length > 0 ? text : null;
+}
+
+function mapRow(row: ObligationRow): {
+  id: number;
+  category: string;
+  title: string;
+  description: string | null;
+  dueDate: string | null;
+  recurrence: string | null;
+  status: string;
