+  it('不正な作成ペイロードは400', async () => {
+    const res = await app.inject({ method: 'POST', url: '/api/obligations', payload: { category: '税務' } });
+    expect(res.statusCode).toBe(400);
+    expect(res.json().error).toBe('title_required');
+  });
+});

diff --git a/packages/core/src/seed/checklist.ts b/packages/core/src/seed/checklist.ts
new file mode 100755
index 0000000000000000000000000000000000000000..1acd07e25424493f5e859402630d37fbed9df86d
--- /dev/null
+++ b/packages/core/src/seed/checklist.ts
@@ -0,0 +1,117 @@
+import { existsSync, readFileSync } from 'node:fs';
+import { dirname, join } from 'node:path';
+import { fileURLToPath } from 'node:url';
+import type { DB } from '../db/connection.js';
+import { parseCsv, type CsvRow } from '../util/csv.js';
+import { createObligation, getObligation, updateObligation, type Obligation } from '../services/obligations.js';
+
+export interface SeedChecklistResult {
+  inserted: number;
+  updated: number;
+  unchanged: number;
+  total: number;
+}
+
+const SOURCE_PATTERN = /S(?:1[0-5]|[1-9])/g;
+
+export function seedChecklist(db: DB, csvPath = defaultChecklistPath()): SeedChecklistResult {
+  const rows = parseCsv(readFileSync(csvPath, 'utf8'));
+  let inserted = 0;
+  let updated = 0;
+  let unchanged = 0;
+
+  const tx = db.transaction(() => {
+    for (const row of rows) {
+      const input = toObligationInput(row);
+      const existing = db
+        .prepare('SELECT id FROM obligations WHERE category = ? AND title = ?')
+        .get(input.category, input.title) as { id: number } | undefined;
+      if (existing) {
+        const current = getObligation(db, existing.id);
+        if (current && sameSeededObligation(current, input)) {
+          unchanged++;
+        } else {
+          updateObligation(db, existing.id, input, 'seed');
+          updated++;
+        }
+      } else {
+        createObligation(db, input, 'seed');
+        inserted++;
+      }
+    }
+  });
+  tx();
+
+  return { inserted, updated, unchanged, total: rows.length };
+}
+
+function toObligationInput(row: CsvRow): {
+  category: string;
+  title: string;
+  description: string;
+  dueDate: null;
+  recurrence: null;
+  status: string;
+  sourceId: string | null;
+  evidenceAttachmentId: null;
+} {
+  const phase = required(row, 'フェーズ');
+  const category = required(row, '分類');
+  const task = required(row, 'タスク');
+  const priority = row['優先度']?.trim() || '未設定';
+  const evidence = row['証跡/成果物']?.trim() || '未設定';
+  const status = normalizeStatus(row['状態']);
+  const sourceId = firstSourceId(row['主な出典'] ?? '');
+
+  return {
+    category,
+    title: task,
+    description: `フェーズ: ${phase}\n優先度: ${priority}\n証跡/成果物: ${evidence}`,
+    dueDate: null,
+    recurrence: null,
+    status,
+    sourceId,
+    evidenceAttachmentId: null,
+  };
+}
+
+function defaultChecklistPath(): string {
+  const candidates = [
+    join(process.cwd(), 'docs', 'reference', 'action_checklist.csv'),
+    join(dirname(fileURLToPath(import.meta.url)), '..', '..', '..', '..', 'docs', 'reference', 'action_checklist.csv'),
+  ];
+  const found = candidates.find((candidate) => existsSync(candidate));
+  if (!found) throw new Error('docs/reference/action_checklist.csv not found');
+  return found;
+}
+
+function required(row: CsvRow, key: string): string {
+  const value = row[key]?.trim();
+  if (!value) throw new Error(`checklist column is required: ${key}`);
+  return value;
+}
+
+function normalizeStatus(value: string | undefined): string {
+  const status = value?.trim();
+  return status && status !== '未' ? status : '未着手';
+}
+
+function firstSourceId(value: string): string | null {
+  return value.match(SOURCE_PATTERN)?.[0] ?? null;
+}
+
+function sameSeededObligation(
+  current: Obligation,
+  next: ReturnType<typeof toObligationInput>,
+): boolean {
+  return (
+    current.category === next.category &&
+    current.title === next.title &&
+    current.description === next.description &&
+    current.dueDate === next.dueDate &&
+    current.recurrence === next.recurrence &&
+    current.status === next.status &&
+    current.sourceId === next.sourceId &&
+    current.evidenceAttachmentId === next.evidenceAttachmentId
+  );
+}
diff --git a/packages/core/src/services/obligations.ts b/packages/core/src/services/obligations.ts
new file mode 100755
index 0000000000000000000000000000000000000000..bf545799442622ccbb6f69063505c40d690c6802
--- /dev/null
+++ b/packages/core/src/services/obligations.ts
@@ -0,0 +1,183 @@
+import { writeAudit } from '../audit.js';
+import type { DB } from '../db/connection.js';
+import { dueStatus, type DueStatus, type IsoDate } from '../util/dates.js';
+
+export interface Obligation {
+  id: number;
+  category: string;
+  title: string;
+  description: string | null;
+  dueDate: IsoDate | null;
+  recurrence: string | null;
+  status: string;
+  sourceId: string | null;
+  evidenceAttachmentId: number | null;
+  createdAt: string;
+}
+
+export interface ObligationWithDueStatus extends Obligation {
+  dueStatus: DueStatus;
+}
+
+export interface CreateObligationInput {
+  category: string;
+  title: string;
+  description?: string | null;
+  dueDate?: IsoDate | null;
+  recurrence?: string | null;
+  status?: string;
+  sourceId?: string | null;
+  evidenceAttachmentId?: number | null;
+}
+
+export type UpdateObligationInput = Partial<CreateObligationInput>;
+
+interface ObligationRow {
+  id: number;
+  category: string;
+  title: string;
+  description: string | null;
+  due_date: string | null;
+  recurrence: string | null;
+  status: string;
+  source_id: string | null;
+  evidence_attachment_id: number | null;
+  created_at: string;
+}
+
+const ENTITY_TYPE = 'obligation';
+
+export function createObligation(db: DB, input: CreateObligationInput, actor = 'local_user'): Obligation {
+  const payload = normalizeCreate(input);
+  const result = db
+    .prepare(
+      `INSERT INTO obligations
+        (category, title, description, due_date, recurrence, status, source_id, evidence_attachment_id)
+       VALUES
+        (@category, @title, @description, @dueDate, @recurrence, @status, @sourceId, @evidenceAttachmentId)`,
+    )
+    .run(payload);
+  const created = getObligationOrThrow(db, Number(result.lastInsertRowid));
+  writeAudit(db, { actor, action: 'create', entityType: ENTITY_TYPE, entityId: created.id, after: created });
+  return created;
+}
+
+export function getObligation(db: DB, id: number): Obligation | null {
+  const row = db.prepare('SELECT * FROM obligations WHERE id = ?').get(id) as ObligationRow | undefined;
+  return row ? mapRow(row) : null;
+}
+
+export function listObligations(db: DB): Obligation[] {
+  return db
+    .prepare('SELECT * FROM obligations ORDER BY due_date IS NULL, due_date ASC, id ASC')
+    .all()
+    .map((row) => mapRow(row as ObligationRow));
+}
+
+export function listWithDueStatus(db: DB, today: IsoDate): ObligationWithDueStatus[] {
+  return listObligations(db).map((obligation) => ({
+    ...obligation,
+    dueStatus: dueStatus(obligation.dueDate, today),
+  }));
+}
+
+export function updateObligation(db: DB, id: number, input: UpdateObligationInput, actor = 'local_user'): Obligation {
+  const before = getObligationOrThrow(db, id);
+  const next = { ...before, ...normalizeUpdate(input) };
+  db.prepare(
+    `UPDATE obligations SET
+       category = @category,
+       title = @title,
+       description = @description,
+       due_date = @dueDate,
+       recurrence = @recurrence,
+       status = @status,
+       source_id = @sourceId,
+       evidence_attachment_id = @evidenceAttachmentId
+     WHERE id = @id`,
+  ).run({
+    id,
+    category: next.category,
+    title: next.title,
+    description: next.description,
+    dueDate: next.dueDate,
+    recurrence: next.recurrence,
+    status: next.status,
+    sourceId: next.sourceId,
+    evidenceAttachmentId: next.evidenceAttachmentId,
+  });
+  const after = getObligationOrThrow(db, id);
+  writeAudit(db, { actor, action: 'update', entityType: ENTITY_TYPE, entityId: id, before, after });
+  return after;
+}
+
+export function updateObligationStatus(db: DB, id: number, status: string, actor = 'local_user'): Obligation {
+  return updateObligation(db, id, { status }, actor);
+}
+
+export function deleteObligation(db: DB, id: number, actor = 'local_user'): void {
+  const before = getObligationOrThrow(db, id);
+  writeAudit(db, { actor, action: 'delete', entityType: ENTITY_TYPE, entityId: id, before });
+  db.prepare('DELETE FROM obligations WHERE id = ?').run(id);
+}
+
+function getObligationOrThrow(db: DB, id: number): Obligation {
+  const obligation = getObligation(db, id);
+  if (!obligation) throw new Error(`obligation not found: ${id}`);
+  return obligation;
+}
+
+function normalizeCreate(input: CreateObligationInput): Required<CreateObligationInput> {
+  const category = requireText(input.category, 'category');
+  const title = requireText(input.title, 'title');
+  return {
+    category,
+    title,
+    description: toNullableText(input.description),
+    dueDate: toNullableText(input.dueDate),
+    recurrence: toNullableText(input.recurrence),
+    status: toNullableText(input.status) ?? '未着手',
+    sourceId: toNullableText(input.sourceId),
+    evidenceAttachmentId: input.evidenceAttachmentId ?? null,
+  };
+}
+
+function normalizeUpdate(input: UpdateObligationInput): UpdateObligationInput {
+  const out: UpdateObligationInput = {};
+  if (input.category !== undefined) out.category = requireText(input.category, 'category');
+  if (input.title !== undefined) out.title = requireText(input.title, 'title');
+  if (input.description !== undefined) out.description = toNullableText(input.description);
+  if (input.dueDate !== undefined) out.dueDate = toNullableText(input.dueDate);
+  if (input.recurrence !== undefined) out.recurrence = toNullableText(input.recurrence);
+  if (input.status !== undefined) out.status = requireText(input.status, 'status');
+  if (input.sourceId !== undefined) out.sourceId = toNullableText(input.sourceId);
+  if (input.evidenceAttachmentId !== undefined) out.evidenceAttachmentId = input.evidenceAttachmentId;
+  return out;
+}
+
+function requireText(value: string | null | undefined, field: string): string {
+  const text = toNullableText(value);
+  if (!text) throw new Error(`${field} is required`);
+  return text;
+}
+
+function toNullableText(value: string | null | undefined): string | null {
+  if (value == null) return null;
+  const text = value.trim();
+  return text.length > 0 ? text : null;
+}
+
+function mapRow(row: ObligationRow): Obligation {
+  return {
+    id: row.id,
+    category: row.category,
+    title: row.title,
+    description: row.description,
+    dueDate: row.due_date,
+    recurrence: row.recurrence,
+    status: row.status,
+    sourceId: row.source_id,
+    evidenceAttachmentId: row.evidence_attachment_id,
+    createdAt: row.created_at,
+  };
+}
diff --git a/packages/core/test/obligations.test.ts b/packages/core/test/obligations.test.ts
