+      });
+  });
+
+  app.get('/api/obligations/:id', async (req, reply) => {
+    const id = routeId(req.params);
+    if (!Number.isInteger(id)) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const obligation = getObligation(app, id);
+    if (!obligation) {
